sql:
SELECT movies.movie_id, movies.title, multimedia.content_type, multimedia.content_url 
FROM movies 
JOIN multimedia ON movies.movie_id = multimedia.movie_id;

SELECT user_id, COUNT(DISTINCT movie_id) AS num_movies_reviewed
FROM user_reviews
GROUP BY user_id;

SELECT COUNT(DISTINCT movie_id) AS total_movies
FROM movies
WHERE rating > 8;

external_knowledge:
Highly rated movies refer to those with an average rating greater than 8; 
"Total views" refers to the sum of all views as recorded in the analytics table;
"Average rating" refers to the mean rating as calculated from user reviews.

